create type public.user_role as enum ('writer', 'producer', 'admin');
create type public.request_status as enum ('pending', 'approved', 'rejected');
create table public.profiles (id uuid primary key references auth.users(id) on delete cascade, role user_role not null default 'writer', full_name text not null, avatar_url text, bio text, verified boolean not null default false, company_name text, designation text, website text, linkedin_url text, imdb_url text, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.genres (id uuid primary key default gen_random_uuid(), name text unique not null, slug text unique not null);
create table public.stories (id uuid primary key default gen_random_uuid(), writer_id uuid not null references public.profiles(id) on delete cascade, title text not null, slug text unique not null, genre_id uuid references public.genres(id), language text not null, story_type text not null, logline text not null, protected_synopsis text not null, cover_url text, age_rating text, mood text, audience text, status text not null default 'draft' check (status in ('draft','published','under_review','suspended')), featured boolean not null default false, views_count integer not null default 0, likes_count integer not null default 0, bookmarks_count integer not null default 0, published_at timestamptz, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), constraint no_full_script_fields check (protected_synopsis !~* '(full script|download pdf|complete screenplay)'));
create table public.tags (id uuid primary key default gen_random_uuid(), name text unique not null);
create table public.story_tags (story_id uuid references public.stories(id) on delete cascade, tag_id uuid references public.tags(id) on delete cascade, primary key (story_id, tag_id));
create table public.bookmarks (user_id uuid references public.profiles(id) on delete cascade, story_id uuid references public.stories(id) on delete cascade, created_at timestamptz default now(), primary key (user_id, story_id));
create table public.likes (user_id uuid references public.profiles(id) on delete cascade, story_id uuid references public.stories(id) on delete cascade, created_at timestamptz default now(), primary key (user_id, story_id));
create table public.story_views (id uuid primary key default gen_random_uuid(), story_id uuid references public.stories(id) on delete cascade, viewer_id uuid references public.profiles(id), ip_hash text, created_at timestamptz default now());
create table public.contact_requests (id uuid primary key default gen_random_uuid(), story_id uuid not null references public.stories(id) on delete cascade, requester_id uuid not null references public.profiles(id) on delete cascade, writer_id uuid not null references public.profiles(id) on delete cascade, message text not null, status request_status not null default 'pending', decided_at timestamptz, created_at timestamptz default now());
create table public.messages (id uuid primary key default gen_random_uuid(), request_id uuid references public.contact_requests(id) on delete cascade, sender_id uuid references public.profiles(id), body text not null, read_at timestamptz, created_at timestamptz default now());
create table public.notifications (id uuid primary key default gen_random_uuid(), user_id uuid references public.profiles(id) on delete cascade, title text not null, body text not null, read_at timestamptz, created_at timestamptz default now());
create table public.verification_documents (id uuid primary key default gen_random_uuid(), profile_id uuid references public.profiles(id) on delete cascade, kind text not null, file_url text not null, status request_status default 'pending', reviewed_by uuid references public.profiles(id), created_at timestamptz default now());
create table public.reports (id uuid primary key default gen_random_uuid(), reporter_id uuid references public.profiles(id), story_id uuid references public.stories(id), reason text not null, status text default 'open', created_at timestamptz default now());
create table public.activity_logs (id uuid primary key default gen_random_uuid(), actor_id uuid references public.profiles(id), action text not null, entity_type text not null, entity_id uuid, metadata jsonb default '{}', created_at timestamptz default now());
create table public.admin_actions (id uuid primary key default gen_random_uuid(), admin_id uuid references public.profiles(id), action text not null, target_profile_id uuid references public.profiles(id), notes text, created_at timestamptz default now());
alter table public.profiles enable row level security;
alter table public.stories enable row level security;
alter table public.contact_requests enable row level security;
alter table public.messages enable row level security;
create policy "published stories are public" on public.stories for select using (status = 'published');
create policy "writers manage own stories" on public.stories for all using (auth.uid() = writer_id) with check (auth.uid() = writer_id);
create policy "profiles are readable" on public.profiles for select using (true);
create policy "users update own profile" on public.profiles for update using (auth.uid() = id) with check (auth.uid() = id);
create policy "request parties can read" on public.contact_requests for select using (auth.uid() in (requester_id, writer_id));
create policy "verified professionals request contact" on public.contact_requests for insert with check (auth.uid() = requester_id and exists (select 1 from public.profiles p where p.id = auth.uid() and p.verified = true and p.role = 'producer'));
create policy "approved parties can message" on public.messages for insert with check (exists (select 1 from public.contact_requests cr where cr.id = request_id and cr.status = 'approved' and auth.uid() in (cr.requester_id, cr.writer_id)));
